#!/usr/bin/env node
'use strict';

const fs = require('fs');
const path = require('path');
const os = require('os');

const SKILLS_DIR = path.join(os.homedir(), '.cursor', 'skills');
const PACKAGE_SKILLS_DIR = path.join(__dirname, '..', 'skills');

const SKILLS = [
  'arjun',
  'meera',
  'priya',
  'zara',
  'noor',
  'anuj',
  'raj',
  'design-critic',
  'ux-ideator',
  'design-personas',
];

// Copies a directory recursively
function copyDir(src, dest) {
  fs.mkdirSync(dest, { recursive: true });
  for (const entry of fs.readdirSync(src, { withFileTypes: true })) {
    const srcPath = path.join(src, entry.name);
    const destPath = path.join(dest, entry.name);
    if (entry.isDirectory()) {
      copyDir(srcPath, destPath);
    } else {
      fs.copyFileSync(srcPath, destPath);
    }
  }
}

function install({ silent = false, force = false } = {}) {
  const log = silent ? () => {} : console.log;
  const warn = silent ? () => {} : console.warn;

  fs.mkdirSync(SKILLS_DIR, { recursive: true });

  const installed = [];
  const skipped = [];
  const errors = [];

  for (const skill of SKILLS) {
    const src = path.join(PACKAGE_SKILLS_DIR, skill);
    const dest = path.join(SKILLS_DIR, skill);

    if (!fs.existsSync(src)) {
      warn(`  ⚠  Skill source not found: ${skill}`);
      errors.push(skill);
      continue;
    }

    // If dest exists and not forcing, skip
    if (fs.existsSync(dest) && !force) {
      skipped.push(skill);
      continue;
    }

    try {
      copyDir(src, dest);
      installed.push(skill);
    } catch (err) {
      warn(`  ✗  Failed to install ${skill}: ${err.message}`);
      errors.push(skill);
    }
  }

  if (installed.length > 0) {
    log(`\n✅ cursor-design-personas installed ${installed.length} skill(s) to ~/.cursor/skills/:`);
    for (const s of installed) log(`   • ${s}`);
  }

  if (skipped.length > 0) {
    log(`\n⏭  Skipped ${skipped.length} already-existing skill(s) (use --force to overwrite):`);
    for (const s of skipped) log(`   • ${s}`);
  }

  if (errors.length > 0) {
    log(`\n✗  ${errors.length} skill(s) failed to install.`);
  }

  if (installed.length > 0 || skipped.length > 0) {
    log(`\n💡 Usage:`);
    log(`   /design-critic   — multi-persona critique (Arjun, Meera, Priya, Zara)`);
    log(`   /ux-ideator      — full ideation workflow (all 7 personas, 6 phases)`);
    log(`   /design-personas — fill in session context before a session\n`);
  }

  return { installed, skipped, errors };
}

function remove({ silent = false } = {}) {
  const log = silent ? () => {} : console.log;

  const removed = [];
  const missing = [];

  for (const skill of SKILLS) {
    const dest = path.join(SKILLS_DIR, skill);
    if (!fs.existsSync(dest)) {
      missing.push(skill);
      continue;
    }
    fs.rmSync(dest, { recursive: true, force: true });
    removed.push(skill);
  }

  if (removed.length > 0) {
    log(`\n🗑  Removed ${removed.length} skill(s) from ~/.cursor/skills/:`);
    for (const s of removed) log(`   • ${s}`);
  }
  if (missing.length > 0) {
    log(`\n   ${missing.length} skill(s) were not installed (nothing to remove).`);
  }
  log('');
}

module.exports = { install, remove, SKILLS };

// Run directly (postinstall)
if (require.main === module) {
  const silent = process.argv.includes('--silent');
  install({ silent });
}

#!/usr/bin/env node
'use strict';

const path = require('path');
const os = require('os');
const { install, remove, SKILLS } = require('../lib/install');

const SKILLS_DIR = path.join(os.homedir(), '.cursor', 'skills');

const HELP = `
cursor-design-personas — 7 AI design personas for Cursor

Usage:
  npx cursor-design-personas [command] [options]

Commands:
  install    Copy all skills to ~/.cursor/skills/  (default)
  remove     Delete installed skills from ~/.cursor/skills/
  list       Show installed skills

Options:
  --force    Overwrite existing skills on install
  --help     Show this help message

Personas installed:
  Arjun      UX Agent (UX Honeycomb critique)
  Meera      Business Agent (retention, ARR, GTM)
  Priya      Feasibility Agent (effort sizing, risks)
  Zara       Delight Agent (Peak-End, one moment)
  Noor       IA Architect (Concept A, minimalist)
  Anuj       Power-User Advocate (Concept B, dense)
  Raj        Arbitrator (stalemate only)

Orchestrating skills:
  design-critic    4-persona critique → SHIP/REVISE/BLOCK
  ux-ideator       6-phase ideation workflow
  design-personas  Session context template

Docs: https://github.com/rishikeshjoshi/cursor-design-personas
`;

const fs = require('fs');

const [,, cmd, ...flags] = process.argv;
const force = flags.includes('--force');

switch (cmd) {
  case undefined:
  case 'install':
    install({ force });
    break;

  case 'remove':
  case 'uninstall':
    remove({});
    break;

  case 'list': {
    console.log('\nInstalled cursor-design-personas skills:\n');
    for (const skill of SKILLS) {
      const dest = `${SKILLS_DIR}/${skill}`;
      const exists = fs.existsSync(dest);
      console.log(`  ${exists ? '✅' : '✗ '} ${skill}`);
    }
    console.log('');
    break;
  }

  case '--help':
  case 'help':
  case '-h':
    console.log(HELP);
    break;

  default:
    console.error(`\nUnknown command: "${cmd}"\n`);
    console.log(HELP);
    process.exit(1);
}

